"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[619],{3034:e=>{e.exports=JSON.parse('{"functions":[{"name":"new","desc":"Creates a new Resonix engine instance. The engine owns the sound buffer,\\nthe occlusion cache, and all registered presets.\\n\\nAll 14 built-in presets (weapons, footsteps, impacts, explosions) are\\nregistered automatically. Additional presets can be registered at any time\\nvia `:RegisterPreset()`.\\n\\n```lua\\nlocal Engine = Resonix.new()\\n```","params":[],"returns":[{"desc":"","lua_type":"Resonix"}],"function_type":"static","source":{"line":77,"path":"docs/Resonix.lua"}},{"name":"RegisterPreset","desc":"Registers a custom emission preset under the given key.\\n\\nOnce registered, the preset can be used with `:EmitPreset()` and\\n`ResonixNet:Fire()`. Both server and client must register custom presets\\nin the **same order** when using ResonixNet \u2014 the hash is assigned by\\nregistration position.\\n\\n```lua\\nEngine:RegisterPreset(\\"Helicopter_Approach\\", {\\n    Intensity  = 75,\\n    Radius     = 500,\\n    Duration   = 10.0,\\n    Frequency  = Resonix.Frequency.Low,\\n    DefaultTag = \\"Helicopter_Approach\\",\\n})\\n```","params":[{"name":"key","desc":"Unique preset identifier. Used as the argument to `:EmitPreset()`.","lua_type":"string"},{"name":"preset","desc":"Preset configuration table.","lua_type":"EmissionPreset"}],"returns":[],"function_type":"method","source":{"line":102,"path":"docs/Resonix.lua"}},{"name":"EmitPreset","desc":"Emits a sound using a registered preset.\\n\\nLooks up the preset by key, constructs a [SoundEmission], stores it in\\nthe buffer, and returns the emission\'s unique ID. Hold onto the ID to\\ncancel the emission early via `:Cancel()`.\\n\\nThe optional `source` argument is an `Instance` excluded from occlusion\\nraycasts \u2014 pass the character or part that produced the sound so its own\\ngeometry does not block the sound it just emitted.\\n\\n```lua\\n-- Simple emit\\nEngine:EmitPreset(\\"Gunshot_Rifle\\", origin, character)\\n\\n-- Long-duration emit that can be cancelled\\nlocal id = Engine:EmitPreset(\\"VendingMachine\\", vendingMachine.Position, vendingMachine)\\n-- ... later:\\nEngine:Cancel(id)\\n```","params":[{"name":"presetKey","desc":"Key of a registered preset.","lua_type":"string"},{"name":"position","desc":"World-space origin of the emission.","lua_type":"Vector3"},{"name":"source","desc":"Optional Instance excluded from occlusion raycasts.","lua_type":"Instance?"},{"name":"tagOverride","desc":"Overrides the preset\'s DefaultTag in query results.","lua_type":"string?"}],"returns":[{"desc":"Unique emission ID.","lua_type":"string"}],"function_type":"method","source":{"line":133,"path":"docs/Resonix.lua"}},{"name":"Emit","desc":"Emits a sound with a fully specified config table.\\n\\nUse this when no preset fits \u2014 for one-off sounds with unusual parameters.\\n`:EmitPreset()` is preferred for any sound that fires more than once.\\n\\n```lua\\nlocal id = Engine:Emit({\\n    Position  = origin,\\n    Intensity = 55,\\n    Radius    = 80,\\n    Duration  = 0.1,\\n    Frequency = Resonix.Frequency.Mid,\\n    Source    = emittingPart,\\n    Tag       = \\"Custom_Sound\\",\\n})\\n```","params":[{"name":"config","desc":"","lua_type":"{ Position: Vector3, Intensity: number, Radius: number, Duration: number, Frequency: string, Source: Instance?, Tag: string?, PresetKey: string? }"}],"returns":[{"desc":"Unique emission ID.","lua_type":"string"}],"function_type":"method","source":{"line":156,"path":"docs/Resonix.lua"}},{"name":"Cancel","desc":"Immediately removes an emission from the buffer.\\n\\nAny `:QueryPosition()` call after this returns will not include the\\ncancelled emission. Occlusion cache entries for this emission are also\\ncleared.\\n\\nReturns `true` if the emission was found and removed, `false` if it had\\nalready expired or was never registered.","params":[{"name":"emissionId","desc":"The ID returned by `:EmitPreset()` or `:Emit()`.","lua_type":"string"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":171,"path":"docs/Resonix.lua"}},{"name":"QueryPosition","desc":"Returns every audible emission at `position` with effective intensity at or\\nabove `minIntensity`.\\n\\nResults are sorted descending by `EffectiveIntensity` \u2014 index `[1]` is\\nalways the loudest stimulus. Each result is a [SoundStimulus] containing\\nthe original emission, computed intensity, direction, distance, and\\nocclusion factor.\\n\\nThe optional `excludeList` lets you exclude specific instances from all\\nocclusion raycasts in this query (e.g., the querying character\'s own model).\\n\\n```lua\\nlocal stimuli = Engine:QueryPosition(listenerPos, 5)\\n\\nfor _, stimulus in stimuli do\\n    if stimulus.Emission.Tag == \\"Gunshot_Rifle\\" then\\n        -- handle gunshot\\n    end\\nend\\n```","params":[{"name":"position","desc":"The listener\'s world position.","lua_type":"Vector3"},{"name":"minIntensity","desc":"Minimum effective intensity threshold (0\u2013100). Stimuli below this are excluded.","lua_type":"number"},{"name":"excludeList","desc":"Optional instances excluded from occlusion raycasts.","lua_type":"{ Instance }?"}],"returns":[{"desc":"Array of SoundStimulus, sorted descending by EffectiveIntensity.","lua_type":"QueryResult"}],"function_type":"method","source":{"line":202,"path":"docs/Resonix.lua"}},{"name":"QueryStrongest","desc":"Returns the single loudest audible stimulus at `position`, or `nil` if\\nnothing at or above `minIntensity` is audible.\\n\\nEquivalent to `Engine:QueryPosition(position, minIntensity)[1]` but\\nslightly more efficient as it stops after finding the strongest result.","params":[{"name":"position","desc":"","lua_type":"Vector3"},{"name":"minIntensity","desc":"","lua_type":"number"},{"name":"excludeList","desc":"","lua_type":"{ Instance }?"}],"returns":[{"desc":"","lua_type":"SoundStimulus?"}],"function_type":"method","source":{"line":216,"path":"docs/Resonix.lua"}},{"name":"IsAudibleAt","desc":"Returns `true` if at least one emission is audible at `position` with\\neffective intensity at or above `minIntensity`.\\n\\nMore efficient than `:QueryPosition()` when you only need a yes/no answer\\n\u2014 it short-circuits on the first qualifying emission rather than\\nevaluating the full set.","params":[{"name":"position","desc":"","lua_type":"Vector3"},{"name":"minIntensity","desc":"","lua_type":"number"},{"name":"excludeList","desc":"","lua_type":"{ Instance }?"}],"returns":[{"desc":"","lua_type":"boolean"}],"function_type":"method","source":{"line":231,"path":"docs/Resonix.lua"}},{"name":"GetStats","desc":"Returns a snapshot of the engine\'s current state for profiling.\\n\\n| Field | Description |\\n|-------|-------------|\\n| `ActiveEmissions` | Number of emissions currently in the buffer. |\\n| `CacheEntries` | Number of occupied occlusion cache slots. |\\n\\n```lua\\nlocal stats = Engine:GetStats()\\nprint(\\"Active:\\", stats.ActiveEmissions, \\"Cache:\\", stats.CacheEntries)\\n```","params":[],"returns":[{"desc":"","lua_type":"{ ActiveEmissions: number, CacheEntries: number }"}],"function_type":"method","source":{"line":250,"path":"docs/Resonix.lua"}},{"name":"GetActiveEmissions","desc":"Returns all currently active [SoundEmission] objects in the buffer.\\n\\nIntended for debug visualisation and tooling. Not for use in hot paths \u2014\\nprefer `:QueryPosition()` for runtime queries.","params":[],"returns":[{"desc":"","lua_type":"{ SoundEmission }"}],"function_type":"method","source":{"line":260,"path":"docs/Resonix.lua"}},{"name":"Destroy","desc":"Destroys the engine and releases all resources.\\n\\nAfter this call the instance is inert \u2014 the buffer is cleared, the cache\\nis cleared, and the background prune task is stopped. Calling any method\\nafter `Destroy()` will error.\\n\\n:::caution\\n`Destroy()` is idempotent \u2014 calling it twice is safe.\\n:::","params":[],"returns":[],"function_type":"method","source":{"line":275,"path":"docs/Resonix.lua"}}],"properties":[{"name":"Frequency","desc":"Re-export of [SoundTypes.Frequency]. Use `Resonix.Frequency.Low`,\\n`Resonix.Frequency.Mid`, or `Resonix.Frequency.High` when registering\\ncustom presets so you only need one require.","lua_type":"{ Low: string, Mid: string, High: string }","source":{"line":44,"path":"docs/Resonix.lua"}},{"name":"Preset","desc":"Re-export of [SoundTypes.Preset]. A frozen table of all built-in preset\\nkey constants. Use these as arguments to `:EmitPreset()` to avoid typos.","lua_type":"{ [string]: string }","source":{"line":52,"path":"docs/Resonix.lua"}},{"name":"Accuracy","desc":"Re-export of `SoundPropagator.Accuracy`. Exposed here so callers only\\nneed one require when passing an explicit accuracy tier to `:QueryPosition()`.","lua_type":"{ Full: string, Simple: string, Skip: string }","source":{"line":60,"path":"docs/Resonix.lua"}}],"types":[],"name":"Resonix","desc":"Acoustic simulation engine for Roblox.\\n\\nResonix manages all active sound emissions. Every query runs inverse-square\\ndistance falloff followed by Beer-Lambert geometric occlusion through world\\ngeometry, and returns a sorted list of [SoundStimulus] objects at the\\nlistener\'s position.\\n\\n```lua\\nlocal Resonix = require(ReplicatedStorage.Resonix)\\n\\nlocal Engine = Resonix.new()\\n\\n-- Emit a sound when an event occurs\\nlocal id = Engine:EmitPreset(\\"Gunshot_Rifle\\", character.HumanoidRootPart.Position, character)\\n\\n-- Query what is audible at a position\\nlocal stimuli = Engine:QueryPosition(listenerPos, 5)\\n\\nfor _, stimulus in stimuli do\\n    print(stimulus.Emission.Tag, stimulus.EffectiveIntensity)\\nend\\n\\n-- Cancel a long-duration emission early\\nEngine:Cancel(id)\\n\\nEngine:Destroy()\\n```","source":{"line":32,"path":"docs/Resonix.lua"}}')}}]);